import javax.xml.parsers.*; // Java XML Parsing API - includes all necessary classes needed to parse an xml file and read its content into a Document object (like DOM, SAX etc.)
   import org.w3c.dom.*;    // W3C recommended way of working with the document objects – contains interfaces for accessing elements in documents by name or type / location hierarchy...etc .- includes necessary classes needed to manipulate an xml data model based on its DTD and Schema (for validation)
   import javax.xml.transform.*;// Allows transformation operations, like changing namespace prefixes of the document nodes – contains interfaces for adding transformers such as 'DOMSource' / ...etc . - includes necessary classes needed to perform those transformations.. etc.,    // Java XML Transform API (to create new documents from an existing one)
   import javax.xml.transform.dom.*;// DOM Source, used with the transformer that will be applied for transformation of source document into target form – contains interfaces such as 'DOMSource' / ...etc . - includes necessary classes needed to add or update elements in a dom tree.. etc.,     // Java XML Transform API (to create new documents from an existing one)
import org.xml.sax.*;       // SAX Parser, used for parsing xml data which is more efficient and lightweight than DOM parser – contains interfaces like 'SAXSource' / ...etc . - includes necessary classes needed to implement this interface.. etc.,    	// XMLReader that can read document content lazily (instead of loading entire doc in memory)